import{_ as t,o as i,c as e,a2 as l}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"评估设计收益、成本、风险与工程约束","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/deconstruction/09-benefit-cost-risk-engineering.md","filePath":"03-interaction-design/notes/deconstruction/09-benefit-cost-risk-engineering.md","lastUpdated":1784248569000}'),s={name:"03-interaction-design/notes/deconstruction/09-benefit-cost-risk-engineering.md"};function n(r,a,d,h,o,p){return i(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="评估设计收益、成本、风险与工程约束" tabindex="-1">评估设计收益、成本、风险与工程约束 <a class="header-anchor" href="#评估设计收益、成本、风险与工程约束" aria-label="Permalink to &quot;评估设计收益、成本、风险与工程约束&quot;">​</a></h1><p>设计方案评估需要同时说明它改善什么任务、需要哪些一次性与持续成本、引入什么用户和系统风险，以及哪些工程条件决定方案能否可靠实现。评估不是用一个加权总分自动选方案，而是把决策前提、证据、不可接受风险和验证方式透明化。</p><h2 id="四个维度" tabindex="-1">四个维度 <a class="header-anchor" href="#四个维度" aria-label="Permalink to &quot;四个维度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>定义</th><th>典型内容</th></tr></thead><tbody><tr><td>收益</td><td>方案在特定条件下带来的可观察改善</td><td>成功率、错误恢复、等待理解、可访问性、业务完成</td></tr><tr><td>成本</td><td>建设、迁移、运行、支持和维护所需资源</td><td>设计、开发、测试、基础设施、内容、培训、运维</td></tr><tr><td>风险</td><td>不确定事件发生后造成的损害</td><td>误操作、数据丢失、隐私、安全、法律、锁定与回滚失败</td></tr><tr><td>工程约束</td><td>当前系统、平台和组织限制的可行范围</td><td>数据模型、接口、异步、性能、权限、兼容与发布方式</td></tr></tbody></table><p>工程约束不是“做不了”的同义词。记录约束的来源、强度、持续时间和改变成本，区分确定不变量、当前实现限制和团队暂时缺少能力。</p><h2 id="评估流程" tabindex="-1">评估流程 <a class="header-anchor" href="#评估流程" aria-label="Permalink to &quot;评估流程&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P[&quot;问题事实与目标&quot;] --&gt; A[&quot;形成多个候选方案&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; B[&quot;定义收益指标和基线&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;拆分全生命周期成本&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; R[&quot;识别风险与控制措施&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; E[&quot;验证工程可行性&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; D[&quot;选择、试点或停止&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; V[&quot;上线后验证与回滚&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>至少保留“保持现状”作为基线。没有候选方案比较时，很难判断复杂设计是否必要。</p><h2 id="收益怎样定义" tabindex="-1">收益怎样定义 <a class="header-anchor" href="#收益怎样定义" aria-label="Permalink to &quot;收益怎样定义&quot;">​</a></h2><h3 id="用户任务收益" tabindex="-1">用户任务收益 <a class="header-anchor" href="#用户任务收益" aria-label="Permalink to &quot;用户任务收益&quot;">​</a></h3><ul><li>更多用户正确完成任务；</li><li>减少错误、重复输入与恢复时间；</li><li>状态、权限和结果更易理解；</li><li>键盘、辅助技术、窄屏和低带宽可完成；</li><li>用户能撤销、恢复或重新确认权威结果。</li></ul><h3 id="产品与业务收益" tabindex="-1">产品与业务收益 <a class="header-anchor" href="#产品与业务收益" aria-label="Permalink to &quot;产品与业务收益&quot;">​</a></h3><ul><li>合格任务完成、采用或留存变化；</li><li>支持请求、人工处理和重复记录减少；</li><li>合规、安全和审计能力提高；</li><li>数据质量和运营可观测性改善。</li></ul><h3 id="工程收益" tabindex="-1">工程收益 <a class="header-anchor" href="#工程收益" aria-label="Permalink to &quot;工程收益&quot;">​</a></h3><ul><li>状态模型统一、重复实现减少；</li><li>请求幂等、故障隔离和恢复能力提高；</li><li>测试可重复、日志可追踪；</li><li>组件和模式可复用。</li></ul><p>收益应写基线、目标、采样点和时间范围。“体验更好”不可验收。相关指标变化不自动证明设计是原因，需要实验、分阶段发布或其他证据。</p><h2 id="成本怎样拆分" tabindex="-1">成本怎样拆分 <a class="header-anchor" href="#成本怎样拆分" aria-label="Permalink to &quot;成本怎样拆分&quot;">​</a></h2><h3 id="一次性建设成本" tabindex="-1">一次性建设成本 <a class="header-anchor" href="#一次性建设成本" aria-label="Permalink to &quot;一次性建设成本&quot;">​</a></h3><ul><li>问题验证、设计、内容和无障碍评审；</li><li>前端、服务端、数据迁移和第三方集成；</li><li>自动化、手工、兼容、安全和性能测试；</li><li>发布、监控、文档和支持准备。</li></ul><h3 id="持续成本" tabindex="-1">持续成本 <a class="header-anchor" href="#持续成本" aria-label="Permalink to &quot;持续成本&quot;">​</a></h3><ul><li>基础设施、存储、队列、通知和第三方费用；</li><li>日志、监控、告警和人工处理；</li><li>多平台、多语言与辅助技术维护；</li><li>数据保留、删除、审计与合规响应；</li><li>组件升级、浏览器变化和技术债。</li></ul><h3 id="迁移与机会成本" tabindex="-1">迁移与机会成本 <a class="header-anchor" href="#迁移与机会成本" aria-label="Permalink to &quot;迁移与机会成本&quot;">​</a></h3><ul><li>旧数据转换和双写；</li><li>老用户学习与支持；</li><li>版本兼容、灰度和回滚；</li><li>延迟其他工作带来的机会成本。</li></ul><p>只估前端页面工作会系统性低估异步任务、权限、数据一致性和运营成本。</p><h2 id="风险怎样记录" tabindex="-1">风险怎样记录 <a class="header-anchor" href="#风险怎样记录" aria-label="Permalink to &quot;风险怎样记录&quot;">​</a></h2><h3 id="风险条目" tabindex="-1">风险条目 <a class="header-anchor" href="#风险条目" aria-label="Permalink to &quot;风险条目&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>触发条件</span></span>
<span class="line"><span>受影响对象与人群</span></span>
<span class="line"><span>可能后果</span></span>
<span class="line"><span>发生可能性及证据</span></span>
<span class="line"><span>影响严重度</span></span>
<span class="line"><span>预防、检测、响应与恢复控制</span></span>
<span class="line"><span>残余风险</span></span>
<span class="line"><span>责任人与复核时间</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="风险分类" tabindex="-1">风险分类 <a class="header-anchor" href="#风险分类" aria-label="Permalink to &quot;风险分类&quot;">​</a></h3><ul><li><strong>任务风险</strong>：错误完成、无法恢复、误导状态。</li><li><strong>数据风险</strong>：丢失、重复、不一致、错误覆盖。</li><li><strong>权限与安全风险</strong>：越权、泄露、重放、注入。</li><li><strong>隐私风险</strong>：过度收集、错误共享、保留过长。</li><li><strong>可访问性风险</strong>：键盘陷阱、状态不可感知、缩放阻塞。</li><li><strong>运营风险</strong>：队列堆积、第三方故障、支持无证据可查。</li><li><strong>迁移风险</strong>：新旧状态不一致、无法回滚。</li></ul><p>高风险项应设置硬性通过条件，不应靠总体加权分被低风险收益抵消。</p><h2 id="工程约束怎样验证" tabindex="-1">工程约束怎样验证 <a class="header-anchor" href="#工程约束怎样验证" aria-label="Permalink to &quot;工程约束怎样验证&quot;">​</a></h2><h3 id="数据与状态" tabindex="-1">数据与状态 <a class="header-anchor" href="#数据与状态" aria-label="Permalink to &quot;数据与状态&quot;">​</a></h3><ul><li>权威数据在哪里，版本怎样控制？</li><li>操作是原子、部分成功还是最终一致？</li><li>幂等键、唯一约束和事务边界是什么？</li><li>刷新、离线、跨设备怎样恢复？</li></ul><h3 id="性能与规模" tabindex="-1">性能与规模 <a class="header-anchor" href="#性能与规模" aria-label="Permalink to &quot;性能与规模&quot;">​</a></h3><ul><li>数据量、并发、响应时间分布与峰值是什么？</li><li>是否需要分页、流式、后台任务或增量更新？</li><li>大列表、长内容和弱网行为怎样？</li></ul><h3 id="平台与兼容" tabindex="-1">平台与兼容 <a class="header-anchor" href="#平台与兼容" aria-label="Permalink to &quot;平台与兼容&quot;">​</a></h3><ul><li>浏览器、原生系统、输入方式和辅助技术支持范围；</li><li>HTML 原生能力与自定义组件成本；</li><li>深链、历史、通知、文件和后台任务能力。</li></ul><h3 id="发布与运维" tabindex="-1">发布与运维 <a class="header-anchor" href="#发布与运维" aria-label="Permalink to &quot;发布与运维&quot;">​</a></h3><ul><li>能否按角色、组织或比例灰度？</li><li>新旧数据能否共存，如何回滚？</li><li>有哪些日志、指标、追踪和告警？</li><li>支持人员怎样定位单个任务结果？</li></ul><h2 id="决策矩阵的正确用法" tabindex="-1">决策矩阵的正确用法 <a class="header-anchor" href="#决策矩阵的正确用法" aria-label="Permalink to &quot;决策矩阵的正确用法&quot;">​</a></h2><p>矩阵用于保持比较维度一致，不应伪装成客观算法。</p><table tabindex="0"><thead><tr><th>维度</th><th>基线</th><th>方案 A</th><th>方案 B</th><th>证据与未知</th></tr></thead><tbody><tr><td>任务成功</td><td></td><td></td><td></td><td></td></tr><tr><td>错误恢复</td><td></td><td></td><td></td><td></td></tr><tr><td>可访问性</td><td></td><td></td><td></td><td></td></tr><tr><td>建设/运行成本</td><td></td><td></td><td></td><td></td></tr><tr><td>数据与安全风险</td><td></td><td></td><td></td><td></td></tr><tr><td>可回滚性</td><td></td><td></td><td></td><td></td></tr></tbody></table><p>若需要评分，必须定义量表、权重来源、敏感性和否决条件。评分只辅助讨论，不能替代关键风险判断和原型验证。</p><h2 id="完整案例-把同步-csv-导入改为异步任务" tabindex="-1">完整案例：把同步 CSV 导入改为异步任务 <a class="header-anchor" href="#完整案例-把同步-csv-导入改为异步任务" aria-label="Permalink to &quot;完整案例：把同步 CSV 导入改为异步任务&quot;">​</a></h2><h3 id="现状与具体证据" tabindex="-1">现状与具体证据 <a class="header-anchor" href="#现状与具体证据" aria-label="Permalink to &quot;现状与具体证据&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>任务：管理员导入 10,000 名成员</span></span>
<span class="line"><span>当前：浏览器同步等待，网关超时 60 秒</span></span>
<span class="line"><span>数据：最近 30 天 1,200 次导入；P95 处理 94 秒</span></span>
<span class="line"><span>失败：18% 页面超时，其中部分后台实际写入</span></span>
<span class="line"><span>支持：73 个“是否导入成功/重复导入”工单</span></span>
<span class="line"><span>约束：写入允许逐行部分成功；邮件通知按成员异步发送</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="候选方案" tabindex="-1">候选方案 <a class="header-anchor" href="#候选方案" aria-label="Permalink to &quot;候选方案&quot;">​</a></h3><ul><li><strong>基线</strong>：保持同步等待，优化单次处理性能。</li><li><strong>方案 A</strong>：上传后创建持久异步任务，任务详情显示处理与逐行结果。</li><li><strong>方案 B</strong>：在浏览器分批上传与处理，每批显示结果。</li></ul><h3 id="收益比较" tabindex="-1">收益比较 <a class="header-anchor" href="#收益比较" aria-label="Permalink to &quot;收益比较&quot;">​</a></h3><table tabindex="0"><thead><tr><th>收益</th><th>基线</th><th>A</th><th>B</th></tr></thead><tbody><tr><td>超过网关时限</td><td>仍有风险</td><td>页面不需持续连接</td><td>单批可控制，但总流程依赖浏览器</td></tr><tr><td>离开与恢复</td><td>弱</td><td>任务 ID 可恢复</td><td>浏览器关闭后恢复复杂</td></tr><tr><td>逐行结果</td><td>可增加</td><td>持久结果与报告</td><td>可逐批显示</td></tr><tr><td>重复提交</td><td>需另做幂等</td><td>任务和行级幂等</td><td>批次与行级幂等更复杂</td></tr><tr><td>运维定位</td><td>现有日志分散</td><td>任务 ID 贯穿追踪</td><td>多批次需要聚合</td></tr></tbody></table><h3 id="成本与工程约束" tabindex="-1">成本与工程约束 <a class="header-anchor" href="#成本与工程约束" aria-label="Permalink to &quot;成本与工程约束&quot;">​</a></h3><p>方案 A 需要任务表、对象存储、队列、工作进程、进度聚合、幂等约束、结果保留、通知、任务详情和告警。持续成本包括队列运行、文件存储、失败重试和支持工具。</p><p>方案 B 前端状态更复杂，浏览器关闭、网络切换和多标签页恢复困难；仍需要服务端批次幂等。它不天然比 A 成本低。</p><h3 id="风险与控制" tabindex="-1">风险与控制 <a class="header-anchor" href="#风险与控制" aria-label="Permalink to &quot;风险与控制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>风险</th><th>控制</th><th>验证</th></tr></thead><tbody><tr><td>同一文件重复创建成员</td><td>导入意图 ID + 成员唯一约束</td><td>重放相同请求</td></tr><tr><td>任务卡死</td><td>心跳、超时、死信和告警</td><td>停止工作进程</td></tr><tr><td>结果与成员数不一致</td><td>事务、逐行状态和对账任务</td><td>固定 CSV 对照数据库</td></tr><tr><td>错误报告泄露邮箱</td><td>权限、短期签名下载、保留期</td><td>角色与过期测试</td></tr><tr><td>状态不可感知</td><td>可见阶段、状态消息和持久详情</td><td>键盘与读屏测试</td></tr><tr><td>无法回滚</td><td>新旧入口灰度；任务数据独立；开关回退</td><td>演练回滚</td></tr></tbody></table><h3 id="决策输出" tabindex="-1">决策输出 <a class="header-anchor" href="#决策输出" aria-label="Permalink to &quot;决策输出&quot;">​</a></h3><p>选择方案 A 进行 5% 管理员灰度，原因是它能处理页面超时、恢复与运维追踪，且数据模型可支持部分成功。否决条件：幂等与权限测试未通过、任务状态无法对账、回滚演练失败。</p><p>目标指标：页面超时不再导致未知结果；重复成员创建为 0；支持人员可用任务 ID 定位；键盘和屏幕阅读器能获取处理与结果。性能目标由当前基线和容量测试确定，不在设计文档中宣称通用阈值。</p><h3 id="失败分支与回滚" tabindex="-1">失败分支与回滚 <a class="header-anchor" href="#失败分支与回滚" aria-label="Permalink to &quot;失败分支与回滚&quot;">​</a></h3><p>队列故障时，新任务进入“等待处理”，不显示失败成功；超过内部阈值触发告警并允许安全暂停新上传。若灰度发现任务状态不一致，关闭新入口，已有任务继续按版本处理；不能删除任务记录或让用户结果消失。</p><h2 id="可执行评估步骤" tabindex="-1">可执行评估步骤 <a class="header-anchor" href="#可执行评估步骤" aria-label="Permalink to &quot;可执行评估步骤&quot;">​</a></h2><ol><li>写清问题事实、目标、基线与不可接受结果。</li><li>提出基线加至少两个可行方案。</li><li>为收益定义任务、业务和工程指标及采样点。</li><li>拆分建设、运行、迁移、支持和机会成本。</li><li>建立风险条目，定义预防、检测、响应和残余风险。</li><li>与工程共同验证数据、状态、性能、兼容、发布和回滚。</li><li>通过原型、技术试验和固定数据验证关键未知。</li><li>记录选择、否决条件、灰度与上线后复核。</li></ol><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>用一个主观分数合并全部维度：保留证据、范围和否决条件。</li><li>只写用户收益，不估数据、运维和支持成本。</li><li>把当前技术实现称为永久约束：说明来源与改变成本。</li><li>只评估成功路径，不估故障、迁移和回滚。</li><li>用前端控制承担权限、幂等和业务不变量。</li><li>指标没有基线、采样点和时间范围。</li><li>方案选定后停止验证，不检查残余风险和生产表现。</li></ul><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>评估“为文档编辑增加自动保存”的基线、方案与风险。</p><p>完成时应满足：</p><ul><li>定义现有保存失败、数据丢失和用户任务基线；</li><li>比较显式保存、定时自动保存和操作级增量保存；</li><li>评估前端、接口、版本、冲突、存储、日志与迁移成本；</li><li>覆盖离线、跨标签页、权限变化、撤销和服务端失败；</li><li>明确本地已保存与云端已同步的状态和辅助技术反馈；</li><li>设定不可接受的数据丢失与覆盖条件；</li><li>有灰度、观测、回滚和固定文档对账测试。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.gov.uk/service-manual/measuring-success/using-data-to-improve-your-service-an-introduction" target="_blank" rel="noreferrer">GOV.UK Service Manual：Using data to improve your service</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/measuring-the-success-of-your-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Measuring the success of your service</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/service-standard/point-14-operate-a-reliable-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Operate a reliable service</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/TR/WCAG22/" target="_blank" rel="noreferrer">W3C：Web Content Accessibility Guidelines (WCAG) 2.2</a>（访问日期：2026-07-17）</li></ul>`,70)])])}const b=t(s,[["render",n]]);export{c as __pageData,b as default};
